const callParticipants = $input.all();
const memberItem = $('Loop Over Members').first().json;
const callIds = [...new Set(callParticipants.map(p => p.json.call_id).filter(id => id))];

if (callIds.length === 0) {
  return [{ json: { member_id: memberItem.id, member_name: memberItem.name, has_calls: false, call_ids_csv: '' } }];
}

return [{ json: { member_id: memberItem.id, member_name: memberItem.name, has_calls: true, call_ids_csv: callIds.join(',') } }];

const scorecardsData = $input.all().map(i => i.json);
const memberItem = $('Loop Over Members').first().json;
const now = new Date();
const periodEnd = now.toISOString().split('T')[0];
const periodStart = new Date(now.getTime() - 28 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const scorecards_array = scorecardsData.map(s => ({
  call_date: s.calls ? s.calls.recorded_at : s.created_at,
  call_type: s.calls ? s.calls.call_type : 'unknown',
  overall_score: s.overall_score,
  summary: s.summary
}));

const avgScore = scorecards_array.length > 0
  ? Math.round((scorecards_array.reduce((sum, s) => sum + (parseFloat(s.overall_score) || 0), 0) / scorecards_array.length) * 10) / 10
  : 0;

const systemPrompt = 'You are a performance analytics coach for WeBuildTrades. You receive a batch of scored call analyses for a single team member over a time period and produce a trend report. Identify: (1) what they consistently do well - reinforce and celebrate; (2) what they consistently do poorly - flag as a pattern not a one-off; (3) whether scores are improving, declining, or plateauing week-over-week; (4) their single most impactful area to work on right now; (5) a specific 2-week improvement challenge. Write in a direct coaching tone. Be specific. Reference actual call dates when making claims. If fewer than 3 calls, set score_trend to INSUFFICIENT_DATA. Return ONLY valid JSON matching exactly: { "member_id": "string", "member_name": "string", "period_start": "string", "period_end": "string", "calls_analyzed": number, "average_score": number, "score_trend": "IMPROVING|DECLINING|PLATEAUING|INSUFFICIENT_DATA", "score_trajectory": [{"call_date":"string","call_type":"string","score":number}], "consistent_strengths": [{"area":"string","evidence":"string","reinforcement_note":"string"}], "consistent_weaknesses": [{"area":"string","frequency":"string","evidence":"string","impact":"string"}], "priority_focus_area": {"area":"string","why_now":"string","two_week_challenge":"string"}, "call_type_breakdown": {"DISCOVERY":{"count":number,"avg_score":number},"FOLLOW_UP":{"count":number,"avg_score":number},"ADS_INTRO":{"count":number,"avg_score":number},"LAUNCH":{"count":number,"avg_score":number},"TEAM":{"count":number,"avg_score":number}}, "manager_briefing": "string" }';

const userPrompt = 'Analyse the following batch of call scorecards for ' + memberItem.name + ' covering the period ' + periodStart + ' to ' + periodEnd + '.\n\nCALL SCORECARDS (ordered oldest to newest):\n' + JSON.stringify(scorecards_array, null, 2) + '\n\nIdentify genuine patterns. Do not manufacture trends from a single outlier. Return only the JSON object.';

return [{
  json: {
    member_id: memberItem.id,
    member_name: memberItem.name,
    period_start: periodStart,
    period_end: periodEnd,
    calls_analyzed: scorecards_array.length,
    average_score: avgScore,
    groq_request_body: {
      model: 'llama-3.3-70b-versatile',
      max_tokens: 2048,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const groqResponse = $input.item.json;
const prevData = $('Build Trend Prompt').item.json;
const responseText = (groqResponse.choices?.[0]?.message?.content || '').trim();
let trendAnalysis;
try {
  trendAnalysis = JSON.parse(responseText);
} catch (e) {
  trendAnalysis = { score_trend: 'INSUFFICIENT_DATA' };
}
return [{
  json: {
    member_id: prevData.member_id,
    period_start: prevData.period_start,
    period_end: prevData.period_end,
    calls_analyzed: prevData.calls_analyzed,
    average_score: trendAnalysis.average_score || prevData.average_score || null,
    score_trend: trendAnalysis.score_trend || 'INSUFFICIENT_DATA',
    analysis_json: trendAnalysis
  }
}];
